// QEMU TCG plugin: drains architectural state and exits when the guest
// executes `csrwi 0x7C0, 0`. Shares hybrid/insn_match.h and
// hybrid/state_abi.h with the vsim side.

#include "hybrid/insn_match.h"
#include "hybrid/reg_names.h"
#include "hybrid/state_abi.h"

#include <qemu-plugin.h>

#include <glib.h>

#include <fcntl.h>
#include <stddef.h>
#include <stdint.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <limits.h>

QEMU_PLUGIN_EXPORT int qemu_plugin_version = QEMU_PLUGIN_VERSION;

typedef struct {
    struct qemu_plugin_register *gpr[32];
    struct qemu_plugin_register *fpr[32];
    struct qemu_plugin_register *pc;

    // M-mode CSRs as exposed by QEMU's gdbstub csr feature.
    struct qemu_plugin_register *mstatus;
    struct qemu_plugin_register *mepc;
    struct qemu_plugin_register *mtvec;
    struct qemu_plugin_register *mcause;
    struct qemu_plugin_register *mtval;
    struct qemu_plugin_register *mscratch;
    struct qemu_plugin_register *medeleg;
    struct qemu_plugin_register *mideleg;
    struct qemu_plugin_register *mip;
    struct qemu_plugin_register *mie;
    struct qemu_plugin_register *mcycle;
    struct qemu_plugin_register *minstret;
    struct qemu_plugin_register *satp;

    struct qemu_plugin_register *pmpcfg[HYBRID_PMP_CFG_NUM];
    struct qemu_plugin_register *pmpaddr[HYBRID_PMP_ADDR_NUM];

    struct qemu_plugin_register *vstart;
    struct qemu_plugin_register *vtype;
    struct qemu_plugin_register *vl;
    struct qemu_plugin_register *vlenb;
    struct qemu_plugin_register *vreg[32];
} VcpuRegs;

static struct qemu_plugin_scoreboard *vcpu_state;
static char *outfile_path;

static struct qemu_plugin_register *find_reg(GArray *regs, const char *name)
{
    for (guint i = 0; i < regs->len; i++) {
        qemu_plugin_reg_descriptor *rd =
            &g_array_index(regs, qemu_plugin_reg_descriptor, i);
        if (g_ascii_strcasecmp(rd->name, name) == 0) {
            return rd->handle;
        }
    }
    return NULL;
}

// Lazily resolves register handles. The plugin's vcpu_init runs before
// QEMU has registered the dynamic gdb coprocessors (FPU, virtual, csr,
// vector), so qemu_plugin_get_registers() returns only the 33 core CPU
// regs at that moment. By the time the entry trigger fires, all dynamic
// features are registered and a fresh call returns the full list.
static void resolve_handles(VcpuRegs *v)
{
    g_autoptr(GArray) regs = qemu_plugin_get_registers();
    for (int i = 0; i < 32; i++) {
        v->gpr[i] = find_reg(regs, hybrid_gpr_names[i]);
        v->fpr[i] = find_reg(regs, hybrid_fpr_names[i]);
    }

// Wire contract between the QEMU TCG plugin and vsim. Both sides write/read
// `struct hybrid_state_v1` byte-for-byte through a shared file.
//
// Stability: never repurpose offsets within a published version. Add new
// fields by consuming bytes from `reserved`, or by introducing v2 alongside.
//
// C and C++ both compile this header.

#ifndef HYBRID_STATE_ABI_H
#define HYBRID_STATE_ABI_H

#include <stdint.h>
#include <stddef.h>

#ifdef __cplusplus
extern "C" {
#endif

#define HYBRID_STATE_MAGIC   0x42594841u  // 'AHYB' little-endian
#define HYBRID_STATE_VERSION 1u

#define HYBRID_FLAG_RV64 (1u << 0)
#define HYBRID_FLAG_FP   (1u << 1)
#define HYBRID_FLAG_V    (1u << 2)

// VLEN upper bound, in bytes. Source of truth: data/configs/ax45mpv_premium.cfg
// which sets `NDS_VLEN 512` (-> 64 bytes per vector register). When that
// configured value changes, this constant must be updated in lock-step so
// the wire-format struct grows or shrinks to match the configured RVV width.
#define HYBRID_VLEN_BYTES_MAX 64

// 64 PMP entries; pmpcfg slots reserved at 16 so the layout works for both
// RV64 (8 entries/CSR) and a future RV32 (4 entries/CSR) packing.
#define HYBRID_PMP_CFG_NUM  16
#define HYBRID_PMP_ADDR_NUM 64

// All fields are naturally 8-byte aligned, so __attribute__((packed)) is
// unnecessary and would force unaligned access codegen. Layout is locked by
// the static_asserts in state_abi_check.h.
struct hybrid_state_v1 {

// rt_mem_loadstore.S
//
// Tier-1 fixture: vsim memory subsystem under load while running from
// foreign architectural state. Exercises store, load-after-store, and a
// modify-store-reload sequence. Memory written in Phase A would be lost
// (no shared mmap in Tier-1), so all initialization happens in Phase B.
//
// Phase A (QEMU1): csrwi 0x7C0, 0 -> drain & exit (no memory work).
// Phase B (vsim):
//   1. buf[i] = (i+1) << 56   for i in 0..7    (8 doublewords at 0x80003000).
//   2. buf[i] += 1.
//   3. x10 = sum(buf[0..7]).
//   Final x10 = 0x2400_0000_0000_0008
//                = (1+2+...+8)<<56 + 8.
// Phase C (QEMU2): verify x10; exit 0 on PASS, 1 on FAIL.

#include "semihost_exit.inc"

.section .text
.globl _start
_start:
    csrwi   0x7C0, 0                 // QEMU1 drains, exits

    // Phase B begin.
    li      t0, 0x80003000           // buf base
    li      t1, 0x0100000000000000   // step = 1 << 56

    // Pass 1: write buf[i] = (i+1) * step.
    mv      t2, t1                   // running value (starts at step for i=0)
    mv      t4, t0                   // walking ptr
    li      t3, 8
1:
    sd      t2, 0(t4)
    add     t2, t2, t1
    addi    t4, t4, 8
    addi    t3, t3, -1
    bnez    t3, 1b

    // Pass 2: buf[i] += 1.
    mv      t4, t0
    li      t3, 8
1:
    ld      t2, 0(t4)
    addi    t2, t2, 1
    sd      t2, 0(t4)
    addi    t4, t4, 8
    addi    t3, t3, -1
    bnez    t3, 1b

    // Pass 3: x10 = sum(buf[0..7]).
    mv      t4, t0
    li      t3, 8
    li      x10, 0
1:
    ld      t2, 0(t4)
    add     x10, x10, t2
    addi    t4, t4, 8
    addi    t3, t3, -1
    bnez    t3, 1b

    csrwi   0x7C0, 1                 // vsim drains, exits 200

phase_c:
    li      t0, 0x2400000000000000
    addi    t0, t0, 8
    beq     x10, t0, pass
    li      a2, 1
    SEMIHOST_EXIT a2
pass:
    li      a2, 0
    SEMIHOST_EXIT a2

// rt_shared_mem.S
//
// Tier-2 fixture: cross-simulator memory survival via shared mmap.
// Unlike Tier-1 fixtures, all three phases see the same backing file via
// QEMU's `-object memory-backend-file,share=on` and vsim's
// `--shared-mem-path`. Memory written in Phase A is visible in Phase B; the
// page Phase B mutates is visible in Phase C.
//
// Phase A (QEMU1, shared mmap): fill 4 KB at 0x80010000 with 0xA5A5..A5.
// Phase B (vsim, same mmap):
//   1. read back; first mismatch -> exit 50.
//   2. XOR every word with 0x5A5A..5A in place; result is all-FF.
// Phase C (QEMU2, same mmap):
//   1. verify all 4 KB == 0xFF; first mismatch -> exit 51.
//   2. exit 0 on PASS.
//
// Distinct exit codes (50, 51) avoid the silent-pass aliasing that a
// running mismatch counter would have when (count mod 256) lands on 0.

#include "semihost_exit.inc"

.section .text
.globl _start
_start:
    // Phase A: fill 512 doublewords at 0x80010000 with 0xA5A5...A5.
    li      t0, 0x80010000
    li      t3, 0xA5A5A5A5A5A5A5A5
    li      t1, 512
1:
    sd      t3, 0(t0)
    addi    t0, t0, 8
    addi    t1, t1, -1
    bnez    t1, 1b

    csrwi   0x7C0, 0                        // QEMU1 drains, exits

    // Phase B: verify Phase A pattern, XOR with 0x5A...5A in place.
    li      t0, 0x80010000
    li      t3, 0xA5A5A5A5A5A5A5A5
    li      t4, 0x5A5A5A5A5A5A5A5A
    li      t1, 512
verify_a:
    ld      t2, 0(t0)
    bne     t2, t3, fail_b
    addi    t0, t0, 8
    addi    t1, t1, -1
    bnez    t1, verify_a

    li      t0, 0x80010000
    li      t1, 512
xor_loop:
    ld      t2, 0(t0)
    xor     t2, t2, t4
    sd      t2, 0(t0)
    addi    t0, t0, 8
    addi    t1, t1, -1
    bnez    t1, xor_loop

    csrwi   0x7C0, 1                        // vsim drains, exits 200

phase_c:
    // Phase C: verify all 4 KB == 0xFFFF...FF through the shared mmap.
    li      t0, 0x80010000
    li      t5, -1                          // sign-extends to 0xFFFF...FF
    li      t1, 512
verify_c:
    ld      t2, 0(t0)
    bne     t2, t5, fail_c
    addi    t0, t0, 8
    addi    t1, t1, -1
    bnez    t1, verify_c

    li      a2, 0
    SEMIHOST_EXIT a2

fail_b:
    li      a2, 50
    SEMIHOST_EXIT a2

fail_c:
    li      a2, 51
    SEMIHOST_EXIT a2
